"use client";

import { useEffect, useMemo, useRef, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import Link from "next/link";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { useToast } from "@/components/ui/use-toast";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { ChevronLeft, ChevronRight, Calendar as CalendarIcon, Search as SearchIcon, UserMinus, ShieldBan, BellOff, Upload } from "lucide-react";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";

const PROVIDERS_STORAGE_KEY = "adminProviders";
const BOOKINGS_STORAGE_KEY = "adminBookings";
const PROVIDER_SETTINGS_KEY = "adminProviderSettings";
const PROVIDER_AVATARS_KEY = "adminProviderAvatars";

type ProviderStatus = "active" | "inactive" | "suspended";

interface Provider {
  id: string;
  name: string;
  email: string;
  phone: string;
  specialization: string;
  rating: number;
  completedJobs: number;
  status: ProviderStatus;
  joinedDate: string;
}

interface Booking {
  id: string;
  customer: { name: string; email: string; phone?: string };
  service: string;
  date: string;
  time: string;
  address?: string;
  status: string;
}

export default function ProviderProfilePage() {
  const params = useParams<{ id: string }>();
  const router = useRouter();
  const [provider, setProvider] = useState<Provider | null>(null);
  const [name, setName] = useState("");
  const [avatarUrl, setAvatarUrl] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const { toast } = useToast();

  // Load provider data
  useEffect(() => {
    const stored = localStorage.getItem(PROVIDERS_STORAGE_KEY);
    if (stored) {
      try {
        const providers = JSON.parse(stored);
        const found = providers.find((p: Provider) => String(p.id) === String(params.id));
        if (found) {
          setProvider(found);
          setName(found.name);
        }
      } catch (error) {
        console.error("Error loading provider data:", error);
      }
    }
  }, [params.id]);

  // Handle name change
  const handleNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newName = e.target.value;
    setName(newName);
    
    if (!provider) return;
    
    try {
      const stored = localStorage.getItem(PROVIDERS_STORAGE_KEY);
      if (stored) {
        const list = JSON.parse(stored);
        const updatedList = list.map((p: Provider) => 
          String(p.id) === String(provider.id) ? { ...p, name: newName } : p
        );
        localStorage.setItem(PROVIDERS_STORAGE_KEY, JSON.stringify(updatedList));
        setProvider(prev => prev ? { ...prev, name: newName } : null);
      }
    } catch (error) {
      console.error("Failed to update provider name:", error);
    }
  };

  // Handle avatar upload
  const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const dataUrl = reader.result as string;
        setAvatarUrl(dataUrl);
        // Save to localStorage
        const avatars = JSON.parse(localStorage.getItem(PROVIDER_AVATARS_KEY) || "{}");
        avatars[params.id as string] = dataUrl;
        localStorage.setItem(PROVIDER_AVATARS_KEY, JSON.stringify(avatars));
      };
      reader.readAsDataURL(file);
    }
  };

  if (!provider) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-cyan-500"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Link href="/admin/providers" aria-label="Back to Providers" className="inline-flex items-center justify-center h-8 w-8 rounded-md hover:bg-muted">
            <ChevronLeft className="h-5 w-5" />
          </Link>
          <div className="relative">
            <Input
              value={name}
              onChange={handleNameChange}
              className="text-xl font-semibold h-10 w-64 border-0 shadow-none focus-visible:ring-1 bg-transparent hover:bg-muted/50 px-2 rounded"
              placeholder="Enter name"
            />
          </div>
        </div>
      </div>

      <Card>
        <CardContent className="pt-6">
          <div className="flex flex-col md:flex-row md:items-start md:justify-between gap-6">
            <div className="flex flex-col items-center md:items-start gap-4 w-full md:w-auto">
              <div className="relative group">
                <div className="h-24 w-24 md:h-32 md:w-32 rounded-full bg-cyan-100 text-cyan-700 flex items-center justify-center font-semibold text-2xl md:text-3xl overflow-hidden">
                  {avatarUrl ? (
                    <img 
                      src={avatarUrl} 
                      alt={provider?.name || 'Provider'} 
                      className="w-full h-full object-cover" 
                    />
                  ) : (
                    provider?.name?.split(' ').map(n => n[0]).join('').toUpperCase() || '?'
                  )}
                </div>
                <input
                  type="file"
                  ref={fileInputRef}
                  onChange={handleAvatarChange}
                  accept="image/*"
                  className="hidden"
                />
                <Button
                  variant="outline"
                  size="sm"
                  className="absolute bottom-0 right-0 rounded-full w-8 h-8 p-0 flex items-center justify-center"
                  onClick={() => fileInputRef.current?.click()}
                >
                  <Upload className="h-4 w-4" />
                </Button>
              </div>
            </div>

            <div className="w-full md:w-[420px] flex md:justify-end">
              <div className="grid grid-cols-1 gap-2 ml-auto self-end">
                <Button
                  variant="outline"
                  size="sm"
                  className="w-64 h-11 px-4 py-3 text-base justify-start rounded-md bg-slate-200 text-slate-800 hover:bg-slate-300 dark:bg-slate-800/60 dark:text-slate-200"
                >
                  <UserMinus className="h-4 w-4 mr-2" />
                  Deactivate
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  className="w-64 h-11 px-4 py-3 text-base justify-start rounded-md bg-amber-100 text-amber-800 hover:bg-amber-200 dark:bg-amber-900/20 dark:text-amber-300"
                >
                  <ShieldBan className="h-4 w-4 mr-2" />
                  Block Access
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  className="w-64 h-11 px-4 py-3 text-base justify-start rounded-md bg-slate-200 text-slate-800 hover:bg-slate-300 dark:bg-slate-800/60 dark:text-slate-200"
                >
                  <BellOff className="h-4 w-4 mr-2" />
                  Unsubscribe
                </Button>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>

      <Tabs defaultValue="dashboard" className="w-full">
        <TabsList className="w-full justify-start gap-2 bg-muted/40 p-0 h-auto rounded-none border-b border-slate-200">
          <TabsTrigger value="dashboard" className="rounded-none px-3 py-3 text-slate-600 data-[state=active]:font-semibold data-[state=active]:text-slate-900 data-[state=active]:border-b-2 data-[state=active]:border-cyan-600">
            Dashboard
          </TabsTrigger>
          <TabsTrigger value="profile" className="rounded-none px-3 py-3 text-slate-600 data-[state=active]:font-semibold data-[state=active]:text-slate-900 data-[state=active]:border-b-2 data-[state=active]:border-cyan-600">
            Profile
          </TabsTrigger>
          <TabsTrigger value="schedule" className="rounded-none px-3 py-3 text-slate-600 data-[state=active]:font-semibold data-[state=active]:text-slate-900 data-[state=active]:border-b-2 data-[state=active]:border-cyan-600">
            Schedule
          </TabsTrigger>
          <TabsTrigger value="settings" className="rounded-none px-3 py-3 text-slate-600 data-[state=active]:font-semibold data-[state=active]:text-slate-900 data-[state=active]:border-b-2 data-[state=active]:border-cyan-600">
            Settings
          </TabsTrigger>
          <TabsTrigger value="payments" className="rounded-none px-3 py-3 text-slate-600 data-[state=active]:font-semibold data-[state=active]:text-slate-900 data-[state=active]:border-b-2 data-[state=active]:border-cyan-600">
            Payments
          </TabsTrigger>
          <TabsTrigger value="notifications" className="rounded-none px-3 py-3 text-slate-600 data-[state=active]:font-semibold data-[state=active]:text-slate-900 data-[state=active]:border-b-2 data-[state=active]:border-cyan-600">
            Notifications
          </TabsTrigger>
        </TabsList>

        <TabsContent value="dashboard">
          <Card>
            <CardHeader>
              <CardTitle>Dashboard</CardTitle>
            </CardHeader>
            <CardContent className="text-sm text-muted-foreground">
              Dashboard content goes here.
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="profile">
          <Card>
            <CardHeader>
              <CardTitle>Profile Information</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label>Email</Label>
                <Input value={provider.email} readOnly />
              </div>
              <div className="space-y-2">
                <Label>Phone</Label>
                <Input value={provider.phone} readOnly />
              </div>
              <div className="space-y-2">
                <Label>Specialization</Label>
                <Input value={provider.specialization} readOnly />
              </div>
              <div className="space-y-2">
                <Label>Status</Label>
                <div className="flex items-center gap-2">
                  <Badge
                    className={provider.status === 'active' ? 'bg-green-100 text-green-800 dark:bg-green-900/20 dark:text-green-400' : 
                            provider.status === 'inactive' ? 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/20 dark:text-yellow-500' : 
                            'bg-red-100 text-red-800 dark:bg-red-900/20 dark:text-red-500'}
                  >
                    {provider.status.charAt(0).toUpperCase() + provider.status.slice(1)}
                  </Badge>
                </div>
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        {/* Add other TabsContent components for each tab value */}

      </Tabs>
    </div>
  );
}